import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface EnergyUsage {
  currentUsage: number;
  unit: string;
  trend: number[];
}

interface RoomTemperature {
  room: string;
  temp: number;
}

interface SmartHomeData {
  connectedDevices: number;
  energyUsage: EnergyUsage;
  roomTemperatures: RoomTemperature[];
}

export default function Widget() {
  const smartHomeData = response.data as SmartHomeData;
  const { energyUsage, roomTemperatures } = smartHomeData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#37474F' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF7043', mb: 1 }}>
              Energy Usage
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FFFFFF' }}>
              {energyUsage.currentUsage} {energyUsage.unit}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: energyUsage.trend,
                  color: '#FF7043',
                  label: 'Energy Trend',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  data: energyUsage.trend.map((_, index) => index),
                  id: 'time',
                },
              ]}
              yAxis={[{ id: 'usage' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="usage"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Stack spacing={1}>
            {roomTemperatures.map((roomTemp, index) => (
              <Box key={index} display="flex" justifyContent="space-between">
                <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
                  {roomTemp.room}
                </Typography>
                <Typography variant="body2" sx={{ color: '#FFFFFF', fontWeight: 500 }}>
                  {roomTemp.temp}°F
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
